#ifdef REACT_NATIVE_DEBUG
// List of layout-only props extracted from ViewProps.kt used to filter out
// component props from Props 1.5 to validate the Props 2.0 output
inline bool isLayoutOnlyProp(const std::string& propName) {
  static const std::vector<std::string> layoutOnlyProps = {
      // Flexbox Alignment
      "alignItems",
      "alignSelf",
      "alignContent",

      // Flexbox Properties
      "flex",
      "flexBasis",
      "flexDirection",
      "flexGrow",
      "flexShrink",
      "flexWrap",
      "justifyContent",

      // Gaps
      "rowGap",
      "columnGap",
      "gap",

      // Display & Position
      "display",
      "position",

      // Positioning
      "right",
      "top",
      "bottom",
      "left",
      "start",
      "end",

      // Dimensions
      "width",
      "height",
      "minWidth",
      "maxWidth",
      "minHeight",
      "maxHeight",

      // Margins
      "margin",
      "marginVertical",
      "marginHorizontal",
      "marginLeft",
      "marginRight",
      "marginTop",
      "marginBottom",
      "marginStart",
      "marginEnd",

      // Paddings
      "padding",
      "paddingVertical",
      "paddingHorizontal",
      "paddingLeft",
      "paddingRight",
      "paddingTop",
      "paddingBottom",
      "paddingStart",
      "paddingEnd",

      // Other
      "collapsable",
  };
  return std::find(layoutOnlyProps.begin(), layoutOnlyProps.end(), propName) !=
      layoutOnlyProps.end();
}
#endif

